#!/bin/bash
#
# Unified ABRIK benchmark suite — runs speed comparisons, runtime breakdowns,
# and accuracy analysis for dense and sparse matrices.
#
# Reproduces exactly the plots generated by plotting/plot_all.m.
#
# Requires: RANDNLA_PROJECT_DIR environment variable
# Output CSVs go to: <script_dir>/results/
#
# Usage:
#   ./run_all_benchmarks.sh           # full suite
#   ./run_all_benchmarks.sh --quick   # quick validation (fewer configs)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"

if [[ -z "${RANDNLA_PROJECT_DIR:-}" ]]; then
    echo "ERROR: RANDNLA_PROJECT_DIR is not set."
    echo "Source RandLAPACK's install.sh or add 'export RANDNLA_PROJECT_DIR=...' to ~/.bashrc"
    exit 1
fi

BENCH_DIR="${RANDNLA_PROJECT_DIR}/build/benchmark-build"
SPEED_BIN="${BENCH_DIR}/ABRIK_speed_comparisons"
BREAKDOWN_BIN="${BENCH_DIR}/ABRIK_runtime_breakdown"
ACCURACY_BIN="${BENCH_DIR}/ABRIK_accuracy_analysis"
OUTPUT_DIR="${SCRIPT_DIR}/results"
MATRIX_DIR="${SCRIPT_DIR}/input_matrices"

PRECISION="double"
TARGET_RANK=10
RUN_GESDD=0

# Dense parameters
DENSE_BSZ="6 6  4 8 16 32 64 128  2 4 8 16 32 64"
# Sparse parameters
SPARSE_BSZ="4 7  4 8 16 32  2 4 8 16 32 64 128"

# Quick mode
if [[ "${1:-}" == "--quick" ]]; then
    DENSE_BSZ="3 3  4 16 64  4 16 64"
    SPARSE_BSZ="2 3  4 16  4 16 64"
fi

# Verify binaries exist
for BIN in "$SPEED_BIN" "$BREAKDOWN_BIN" "$ACCURACY_BIN"; do
    if [[ ! -x "$BIN" ]]; then
        echo "ERROR: $(basename $BIN) not found at $BIN"
        echo "Build: cd $BENCH_DIR && cmake --build . -j\$(nproc)"
        exit 1
    fi
done

mkdir -p "$OUTPUT_DIR"

echo "=========================================="
echo " ABRIK Benchmark Suite"
echo "=========================================="
echo ""

START_TIME=$(date +%s)

# ---- Dense speed comparisons ----
echo ">>> Dense speed: Mat 1"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat1.txt" \
    $TARGET_RANK $RUN_GESDD $DENSE_BSZ

echo ">>> Dense speed: Mat 6"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat6.txt" \
    $TARGET_RANK $RUN_GESDD $DENSE_BSZ

# ---- Dense runtime breakdowns ----
echo ">>> Dense breakdown: Mat 1"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat1.txt" \
    1 $DENSE_BSZ

echo ">>> Dense breakdown: Mat 6"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat6.txt" \
    1 $DENSE_BSZ

# ---- Sparse speed comparisons (cqrrt) ----
echo ">>> Sparse speed (cqrrt): CurlCurl half"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    $TARGET_RANK $RUN_GESDD $SPARSE_BSZ 0.5 1

echo ">>> Sparse speed (cqrrt): CurlCurl full"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    $TARGET_RANK $RUN_GESDD $SPARSE_BSZ 1.0 1

# ---- Sparse runtime breakdowns (cqrrt) ----
echo ">>> Sparse breakdown (cqrrt): CurlCurl half"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    1 $SPARSE_BSZ 0.5 1

echo ">>> Sparse breakdown (cqrrt): CurlCurl full"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    1 $SPARSE_BSZ 1.0 1

# ---- Sparse speed comparisons (geqrf, no cqrrt) ----
echo ">>> Sparse speed (geqrf): CurlCurl half"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    $TARGET_RANK $RUN_GESDD $SPARSE_BSZ 0.5

echo ">>> Sparse speed (geqrf): CurlCurl full"
"$SPEED_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    $TARGET_RANK $RUN_GESDD $SPARSE_BSZ

# ---- Sparse runtime breakdowns (geqrf, no cqrrt) ----
echo ">>> Sparse breakdown (geqrf): CurlCurl half"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    1 $SPARSE_BSZ 0.5

echo ">>> Sparse breakdown (geqrf): CurlCurl full"
"$BREAKDOWN_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/CurlCurl_1.mtx" \
    1 $SPARSE_BSZ

# ---- Accuracy analysis ----
echo ">>> Accuracy: Mat 1 (b=4, mm=32)"
"$ACCURACY_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat1.txt" \
    10000 10000 4 32

echo ">>> Accuracy: Mat 6 (b=16, mm=64)"
"$ACCURACY_BIN" $PRECISION "$OUTPUT_DIR" \
    "$MATRIX_DIR/10000x10000_rank_10000/ABRIK_test_mat6.txt" \
    10000 10000 16 64

END_TIME=$(date +%s)
TOTAL=$((END_TIME - START_TIME))
echo ""
echo "=========================================="
echo " All benchmarks complete!"
echo " Total time: ${TOTAL}s ($(( TOTAL / 60 ))m $(( TOTAL % 60 ))s)"
echo " Results in: $OUTPUT_DIR"
echo "=========================================="
